/**
 * Strand Design System — Interactive Reference
 *
 * A beautiful, scrollable showcase of every token in the TwelveLabs design system.
 * Every color, radius, spacing, font, and component uses Strand Tailwind tokens.
 * Devs spin this up to explore and trust the system before building with it.
 */

import { useState, useEffect, useRef } from 'react'

// Load all SVG icons from the icons directory via Vite glob import
const iconModules = import.meta.glob('../../icons/*.svg', { query: '?raw', import: 'default', eager: true }) as Record<string, string>
const ALL_ICON_SVGS = Object.entries(iconModules)
  .map(([path, svg]) => {
    const name = path.replace(/^.*\/icons\//, '').replace('.svg', '')
    const label = name.split('-').map(w => w[0].toUpperCase() + w.slice(1)).join(' ')
    return { name, label, svg }
  })
  .sort((a, b) => a.name.localeCompare(b.name))

// ---------------------------------------------------------------------------
// Dark mode hook — persists preference to localStorage
// ---------------------------------------------------------------------------

function useDarkMode(): [boolean, () => void] {
  const [dark, setDark] = useState(() => {
    if (typeof window === 'undefined') return false
    const stored = localStorage.getItem('strand-dark-mode')
    if (stored !== null) return stored === 'true'
    return window.matchMedia('(prefers-color-scheme: dark)').matches
  })

  useEffect(() => {
    const root = document.documentElement
    if (dark) {
      root.classList.add('dark')
    } else {
      root.classList.remove('dark')
    }
    localStorage.setItem('strand-dark-mode', String(dark))
  }, [dark])

  const toggle = () => setDark((prev) => !prev)
  return [dark, toggle]
}

