// ---------------------------------------------------------------------------
// Utility: copy to clipboard
// ---------------------------------------------------------------------------

function CopyButton({ text }: { text: string }) {
  const [copied, setCopied] = useState(false)
  return (
    <button
      onClick={() => { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 1200) }}
      className="opacity-0 group-hover:opacity-100 transition-opacity text-[10px] font-mono text-text-tertiary hover:text-text-secondary"
    >
      {copied ? 'Copied' : 'Copy'}
    </button>
  )
}

// ---------------------------------------------------------------------------
// Section: Hero
// ---------------------------------------------------------------------------

function Hero() {
  return (
    <section className="pt-10 lg:pt-20 pb-8 lg:pb-16">
      <h1 className="text-h3 md:text-h1 font-brand text-text-primary mb-4">Strand Design System</h1>
      <p className="text-h5 text-text-secondary font-system max-w-2xl leading-relaxed mb-6">
        The single source of truth for TwelveLabs product UI. Strand is the design token layer that
        weaves every color, radius, spacing, and typographic decision into a unified system &mdash; like
        individual strands forming a thread. Every token below maps directly to a Tailwind class and
        traces back to our Figma source file.
      </p>
      <p className="text-base text-text-secondary font-system max-w-2xl leading-relaxed mb-6">
        The name <em>Strand</em> reflects how design tokens are the fundamental fibers of our visual
        language. Just as strands of DNA encode a biological blueprint, Strand encodes the visual genome
        of TwelveLabs products &mdash; ensuring consistency from Figma to production across every surface.
      </p>
      <p className="text-base text-text-secondary font-system max-w-2xl leading-relaxed mb-8">
        What you see here is aspirational &mdash; a bare minimum foundation. It will need plenty of
        improvements and bug fixes over time, but even in this early form it will immediately uplevel
        brand coherence across the different demos and apps we produce.
      </p>
      <div className="flex items-center gap-3 md:gap-6 flex-wrap text-sm text-text-tertiary font-mono">
        <span>packages/strand/</span>
        <span className="w-1 h-1 rounded-full bg-border" />
        <span>Tailwind v3</span>
        <span className="w-1 h-1 rounded-full bg-border" />
        <span>Figma-synced</span>
      </div>
    </section>
  )
}

