function Swatch({ bg, hex, name, tailwind, dark = false }: { bg: string; hex: string; name: string; tailwind: string; dark?: boolean }) {
  return (
    <div className="group flex flex-col items-center gap-1.5">
      <div className={`w-full aspect-square rounded-lg ${bg} ${dark ? '' : 'border border-border-light'} transition-transform hover:scale-105`} />
      <span className="text-xs font-medium text-text-primary truncate w-full text-center">{name}</span>
      <span className="text-[10px] font-mono text-text-tertiary">{hex}</span>
      <CopyButton text={tailwind} />
    </div>
  )
}

